class Bird { fly(): void { } }
class Duck extends Bird { quack(): void { } }
class RubberDuck extends Duck {
  fly(): void { throw new Error('Cannot fly'); }
}
class RocketDuck extends Duck {
  fly(): void { /* custom rocket fly */ }
}

